ALLOWED_CSV_EXTS = {".csv"}

TRAIN_LOCK = threading.Lock()


def ensure_dirs():
    for p in [BASE_DIR, DATA_DIR, UPLOADS_DIR, IMAGES_DIR, RUNS_DIR, MODELS_DIR, os.path.join(MODELS_DIR, MODEL_NAME), MODEL_REGISTRY_DIR]:
        os.makedirs(p, exist_ok=True)
    os.makedirs(CURRENT_MODEL_DIR, exist_ok=True)


def utc_ts() -> int:
    return int(time.time())


def safe_ext(path: str) -> str:
    return os.path.splitext(path)[1].lower()


def gen_id() -> str:
    return uuid.uuid4().hex


def read_limited(file: UploadFile, limit: int) -> bytes:
    data = file.file.read(limit + 1)
    if len(data) > limit:
        raise HTTPException(status_code=413, detail="Upload too large")
    return data


def sha256_bytes(b: bytes) -> str:
    import hashlib
    h = hashlib.sha256()
    h.update(b)
    return h.hexdigest()


def init_db():
    con = sqlite3.connect(DB_PATH)
    con.execute("""
    CREATE TABLE IF NOT EXISTS examples (
        id TEXT PRIMARY KEY,
        created_at INTEGER NOT NULL,
        source TEXT NOT NULL,
        label TEXT NOT NULL,
        image_path TEXT NOT NULL,
        image_sha256 TEXT NOT NULL,
        width INTEGER,
        height INTEGER,
        meta_json TEXT
    )
    """)
    con.execute("""
    CREATE INDEX IF NOT EXISTS idx_examples_label ON examples(label)
    """)
    con.execute("""
    CREATE TABLE IF NOT EXISTS uploads (
        id TEXT PRIMARY KEY,
        created_at INTEGER NOT NULL,
        kind TEXT NOT NULL,
        original_filename TEXT,
        stored_path TEXT NOT NULL,
        sha256 TEXT NOT NULL,
        meta_json TEXT
    )
    """)
    con.execute("""
    CREATE TABLE IF NOT EXISTS training_runs (
        id TEXT PRIMARY KEY,
        created_at INTEGER NOT NULL,
        status TEXT NOT NULL,
        params_json TEXT,
        metrics_json TEXT,
        model_dir TEXT,
        error TEXT
    )
    """)
    con.execute("""
    CREATE TABLE IF NOT EXISTS model_versions (
        id TEXT PRIMARY KEY,
        created_at INTEGER NOT NULL,
        run_id TEXT NOT NULL,
        model_dir TEXT NOT NULL,
        metrics_json TEXT,
        notes TEXT
    )
    """)
    con.commit()
    con.close()


def db_execute(query: str, args: tuple = ()):
    con = sqlite3.connect(DB_PATH)
    cur = con.execute(query, args)
    con.commit()
    con.close()
    return cur


def db_query(query: str, args: tuple = ()) -> List[tuple]:
    con = sqlite3.connect(DB_PATH)
    cur = con.execute(query, args)
    rows = cur.fetchall()
    con.close()
    return rows


def save_upload(kind: str, filename: Optional[str], content: bytes, meta: Optional[dict] = None) -> Dict[str, Any]:
    up_id = gen_id()
    ext = safe_ext(filename or "")
    stored_name = f"{up_id}{ext if ext else ''}"
    stored_path = os.path.join(UPLOADS_DIR, stored_name)
    with open(stored_path, "wb") as f:
        f.write(content)
    digest = sha256_bytes(content)
    db_execute(
        "INSERT INTO uploads (id, created_at, kind, original_filename, stored_path, sha256, meta_json) VALUES (?, ?, ?, ?, ?, ?, ?)",
        (up_id, utc_ts(), kind, filename, stored_path, digest, json.dumps(meta or {})),
    )
    return {"upload_id": up_id, "stored_path": stored_path, "sha256": digest}


def normalize_label(label: str) -> str:
    label = (label or "").strip()
    if not label:
        raise HTTPException(status_code=400, detail="Empty label")
    if len(label) > 128:
        raise HTTPException(status_code=400, detail="Label too long")
    return label


def save_image_example(image_bytes: bytes, label: str, source: str, meta: Optional[dict] = None) -> Dict[str, Any]:
    label = normalize_label(label)
    ex_id = gen_id()
    digest = sha256_bytes(image_bytes)

    # Load image for validation and dimensions
    try:
        im = Image.open(io.BytesIO(image_bytes))
        im = im.convert("RGB")
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image")

    w, h = im.size
    label_dir = os.path.join(IMAGES_DIR, label)
    os.makedirs(label_dir, exist_ok=True)
    image_path = os.path.join(label_dir, f"{ex_id}.jpg")
    im.save(image_path, format="JPEG", quality=95)

    db_execute(
        "INSERT INTO examples (id, created_at, source, label, image_path, image_sha256, width, height, meta_json) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
        (ex_id, utc_ts(), source, label, image_path, digest, w, h, json.dumps(meta or {})),
    )
    return {"example_id": ex_id, "label": label, "image_path": image_path, "sha256": digest, "width": w, "height": h}


def parse_csv_and_ingest(csv_path: str, source: str, base_path: Optional[str] = None) -> Dict[str, Any]:
    df = pd.read_csv(csv_path)
    cols = {c.lower(): c for c in df.columns}
    if "label" not in cols:
        raise HTTPException(status_code=400, detail="CSV must contain a 'label' column")
    label_col = cols["label"]

    path_col = None
    bytes_col = None
    if "image_path" in cols:
        path_col = cols["image_path"]
    elif "path" in cols:
        path_col = cols["path"]
    if "image_bytes_b64" in cols:
        bytes_col = cols["image_bytes_b64"]

    if not path_col and not bytes_col:
        raise HTTPException(status_code=400, detail="CSV must contain 'image_path' (or 'path') or 'image_bytes_b64'")

    imported = 0
    failed = 0
    errors = []

    for idx, row in df.iterrows():
        try:
            label = normalize_label(str(row[label_col]))
            meta = {}
            if "meta_json" in cols and pd.notna(row[cols["meta_json"]]):
                try:
                    meta = json.loads(row[cols["meta_json"]])
                except Exception:
                    meta = {"meta_raw": str(row[cols["meta_json"]])}

            if bytes_col and pd.notna(row[bytes_col]):
                import base64
                b = base64.b64decode(str(row[bytes_col]), validate=False)
                save_image_example(b, label=label, source=source, meta=meta)
                imported += 1
                continue

            p = str(row[path_col]) if path_col else ""
            p = p.strip()
            if not p:
                raise ValueError("empty path")
            if base_path and not os.path.isabs(p):
                p = os.path.join(base_path, p)
            if not os.path.isfile(p):
                raise ValueError(f"file not found: {p}")
            if safe_ext(p) not in ALLOWED_IMAGE_EXTS:
                raise ValueError(f"unsupported image ext: {p}")
            with open(p, "rb") as f:
                b = f.read()
            save_image_example(b, label=label, source=source, meta=meta)
            imported += 1
        except Exception as e:
            failed += 1
            if len(errors) < 50:
                errors.append({"row": int(idx), "error": str(e)})

    return {"imported": imported, "failed": failed, "errors": errors}


def list_labels_and_counts() -> List[Dict[str, Any]]:
    rows = db_query("SELECT label, COUNT(*) FROM examples GROUP BY label ORDER BY COUNT(*) DESC, label ASC")
    return [{"label": r[0], "count": r[1]} for r in rows]


def total_examples() -> int:
    rows = db_query("SELECT COUNT(*) FROM examples")
    return int(rows[0][0]) if rows else 0


def get_all_examples() -> List[Tuple[str, str]]:
    rows = db_query("SELECT image_path, label FROM examples")
    return [(r[0], r[1]) for r in rows]


def build_model(num_classes: int, image_size: int, lr: float) -> tf.keras.Model:
    base = tf.keras.applications.MobileNetV2(
        input_shape=(image_size, image_size, 3),
        include_top=False,
        weights="imagenet",
    )
    base.trainable = False

    inputs = tf.keras.Input(shape=(image_size, image_size, 3))
    x = tf.keras.applications.mobilenet_v2.preprocess_input(inputs)
    x = base(x, training=False)
    x = tf.keras.layers.GlobalAveragePooling2D()(x)
    x = tf.keras.layers.Dropout(0.2)(x)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)
    model = tf.keras.Model(inputs, outputs)

    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=lr),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model


def build_dataset(paths: List[str], labels: List[int], image_size: int, batch_size: int, training: bool) -> tf.data.Dataset:
    path_ds = tf.data.Dataset.from_tensor_slices(paths)
    label_ds = tf.data.Dataset.from_tensor_slices(tf.cast(labels, tf.int32))
    ds = tf.data.Dataset.zip((path_ds, label_ds))

    def _load(path, y):
        img_bytes = tf.io.read_file(path)
        img = tf.io.decode_image(img_bytes, channels=3, expand_animations=False)
        img = tf.image.resize(img, [image_size, image_size], method=tf.image.ResizeMethod.BILINEAR)
        img = tf.cast(img, tf.float32)
        return img, y

    ds = ds.map(_load, num_parallel_calls=tf.data.AUTOTUNE)

    if training:
        def _aug(x, y):
            x = tf.image.random_flip_left_right(x)
            x = tf.image.random_brightness(x, max_delta=0.10)
            x = tf.image.random_contrast(x, lower=0.9, upper=1.1)
            return x, y
        ds = ds.shuffle(min(len(paths), 4096), reshuffle_each_iteration=True)
        ds = ds.map(_aug, num_parallel_calls=tf.data.AUTOTUNE)

    ds = ds.batch(batch_size).prefetch(tf.data.AUTOTUNE)
    return ds


def train_model(params: Dict[str, Any]) -> Dict[str, Any]:
    with TRAIN_LOCK:
        run_id = gen_id()
        run_dir = os.path.join(RUNS_DIR, run_id)
        os.makedirs(run_dir, exist_ok=True)

        db_execute(
            "INSERT INTO training_runs (id, created_at, status, params_json) VALUES (?, ?, ?, ?)",
            (run_id, utc_ts(), "running", json.dumps(params)),
        )

        try:
            examples = get_all_examples()
            if len(examples) < int(params.get("min_examples_to_train", DEFAULT_MIN_EXAMPLES_TO_TRAIN)):
                raise RuntimeError(f"Not enough examples to train. Have {len(examples)}")

            paths = [p for p, _ in examples]
            labels_str = [l for _, l in examples]
            unique_labels = sorted(set(labels_str))
            if len(unique_labels) < 2:
                raise RuntimeError("Need at least 2 labels/classes to train")

            label_to_id = {l: i for i, l in enumerate(unique_labels)}
            y = np.array([label_to_id[l] for l in labels_str], dtype=np.int32)

            rng = np.random.default_rng(int(params.get("seed", 42)))
            idx = np.arange(len(paths))
            rng.shuffle(idx)
            paths = [paths[i] for i in idx]
            y = y[idx]

            val_split = float(params.get("val_split", 0.2))
            val_n = max(1, int(len(paths) * val_split))
            train_paths, val_paths = paths[val_n:], paths[:val_n]
            train_y, val_y = y[val_n:], y[:val_n]

            image_size = int(params.get("image_size", DEFAULT_IMAGE_SIZE))
            batch_size = int(params.get("batch_size", DEFAULT_BATCH_SIZE))
            epochs = int(params.get("epochs", DEFAULT_EPOCHS))
            lr = float(params.get("lr", DEFAULT_LR))

            train_ds = build_dataset(train_paths, train_y.tolist(), image_size, batch_size, training=True)
            val_ds = build_dataset(val_paths, val_y.tolist(), image_size, batch_size, training=False)

            model = build_model(num_classes=len(unique_labels), image_size=image_size, lr=lr)

            callbacks = [
                tf.keras.callbacks.EarlyStopping(monitor="val_accuracy", patience=3, mode="max", restore_best_weights=True),
                tf.keras.callbacks.ModelCheckpoint(filepath=os.path.join(run_dir, "checkpoint.keras"), monitor="val_accuracy", save_best_only=True, mode="max"),
            ]

            history = model.fit(train_ds, validation_data=val_ds, epochs=epochs, callbacks=callbacks, verbose=1)

            eval_metrics = model.evaluate(val_ds, verbose=0)
            metrics = dict(zip(model.metrics_names, [float(x) for x in eval_metrics]))
            metrics["history"] = {k: [float(v) for v in vals] for k, vals in history.history.items()}
            metrics["num_examples"] = int(len(paths))
            metrics["num_train"] = int(len(train_paths))
            metrics["num_val"] = int(len(val_paths))
            metrics["labels"] = unique_labels

            export_dir = os.path.join(MODEL_REGISTRY_DIR, f"{utc_ts()}_{run_id}")
            os.makedirs(export_dir, exist_ok=True)
            model.save(os.path.join(export_dir, "model.keras"))

            with open(os.path.join(export_dir, "labels.json"), "w", encoding="utf-8") as f:
                json.dump({"labels": unique_labels, "image_size": image_size}, f)

            # Promote to current
            tmp_current = CURRENT_MODEL_DIR + "_tmp"
            if os.path.exists(tmp_current):
                shutil.rmtree(tmp_current, ignore_errors=True)
            os.makedirs(tmp_current, exist_ok=True)
            shutil.copy2(os.path.join(export_dir, "model.keras"), os.path.join(tmp_current, "model.keras"))
            shutil.copy2(os.path.join(export_dir, "labels.json"), os.path.join(tmp_current, "labels.json"))
            if os.path.exists(CURRENT_MODEL_DIR):
                shutil.rmtree(CURRENT_MODEL_DIR, ignore_errors=True)
            os.rename(tmp_current, CURRENT_MODEL_DIR)

            model_version_id = gen_id()
            db_execute(
                "INSERT INTO model_versions (id, created_at, run_id, model_dir, metrics_json, notes) VALUES (?, ?, ?, ?, ?, ?)",
                (model_version_id, utc_ts(), run_id, export_dir, json.dumps(metrics), params.get("notes", "")),
            )

            db_execute(
                "UPDATE training_runs SET status=?, metrics_json=?, model_dir=? WHERE id=?",
                ("succeeded", json.dumps(metrics), export_dir, run_id),
            )

            return {"run_id": run_id, "status": "succeeded", "metrics": metrics, "model_dir": export_dir, "model_version_id": model_version_id}
        except Exception as e:
            db_execute(
                "UPDATE training_runs SET status=?, error=? WHERE id=?",
                ("failed", str(e), run_id),
            )
            raise


def load_current_model() -> Tuple[tf.keras.Model, Dict[str, Any]]:
    model_path = os.path.join(CURRENT_MODEL_DIR, "model.keras")
    labels_path = os.path.join(CURRENT_MODEL_DIR, "labels.json")
    if not os.path.exists(model_path) or not os.path.exists(labels_path):
        raise HTTPException(status_code=404, detail="No current model. Train first.")
    model = tf.keras.models.load_model(model_path)
    with open(labels_path, "r", encoding="utf-8") as f:
        info = json.load(f)
    return model, info


def predict_image_bytes(image_bytes: bytes) -> Dict[str, Any]:
    model, info = load_current_model()
    labels = info["labels"]
    image_size = int(info.get("image_size", DEFAULT_IMAGE_SIZE))

    try:
        im = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image")

    im = im.resize((image_size, image_size))
    arr = np.asarray(im).astype(np.float32)
    x = np.expand_dims(arr, axis=0)

    preds = model.predict(x, verbose=0)[0]
    topk = int(min(5, len(labels)))
    idxs = np.argsort(-preds)[:topk]
    results = [{"label": labels[int(i)], "score": float(preds[int(i)])} for i in idxs]
    return {"topk": results}


