ensure_dirs()
init_db()

app = FastAPI(title="Community-Driven Image Classification Training API", version="1.0")


@app.get("/health")
def health():
    return {"ok": True, "time": utc_ts(), "total_examples": total_examples()}


@app.get("/stats")
def stats():
    return {
        "total_examples": total_examples(),
        "labels": list_labels_and_counts(),
        "has_current_model": os.path.exists(os.path.join(CURRENT_MODEL_DIR, "model.keras")),
    }


@app.post("/upload/example")
async def upload_example(
    label: str = Form(...),
    image: UploadFile = File(...),
    contributor_id: Optional[str] = Form(None),
):
    ext = safe_ext(image.filename or "")
    if ext and ext not in ALLOWED_IMAGE_EXTS:
        raise HTTPException(status_code=400, detail=f"Unsupported image extension: {ext}")

    content = read_limited(image, MAX_UPLOAD_BYTES)
    save_upload("image", image.filename, content, meta={"contributor_id": contributor_id})
    ex = save_image_example(content, label=label, source="api_upload", meta={"contributor_id": contributor_id})
    return JSONResponse(ex)


@app.post("/upload/csv")
async def upload_csv(
    csv: UploadFile = File(...),
    contributor_id: Optional[str] = Form(None),
    base_path: Optional[str] = Form(None),
):
    ext = safe_ext(csv.filename or "")
    if ext not in ALLOWED_CSV_EXTS:
        raise HTTPException(status_code=400, detail=f"Unsupported CSV extension: {ext}")

    content = read_limited(csv, MAX_UPLOAD_BYTES)
    up = save_upload("csv", csv.filename, content, meta={"contributor_id": contributor_id, "base_path": base_path})

    result = parse_csv_and_ingest(up["stored_path"], source="csv_upload", base_path=base_path)
    return JSONResponse({"upload": up, "ingest": result})


@app.post("/train")
def trigger_train(
    epochs: int = Form(DEFAULT_EPOCHS),
    batch_size: int = Form(DEFAULT_BATCH_SIZE),
    image_size: int = Form(DEFAULT_IMAGE_SIZE),
    lr: float = Form(DEFAULT_LR),
    val_split: float = Form(0.2),
    seed: int = Form(42),
    min_examples_to_train: int = Form(DEFAULT_MIN_EXAMPLES_TO_TRAIN),
    notes: str = Form(""),
):
    params = {
        "epochs": int(epochs),
        "batch_size": int(batch_size),
        "image_size": int(image_size),
        "lr": float(lr),
        "val_split": float(val_split),
        "seed": int(seed),
        "min_examples_to_train": int(min_examples_to_train),
        "notes": notes,
    }
    result = train_model(params)
    return JSONResponse(result)


@app.get("/runs")
def list_runs(limit: int = 20):
    limit = max(1, min(200, int(limit)))
    rows = db_query("SELECT id, created_at, status, model_dir, metrics_json, error FROM training_runs ORDER BY created_at DESC LIMIT ?", (limit,))
    out = []
    for r in rows:
        metrics = None
        if r[4]:
            try:
                metrics = json.loads(r[4])
            except Exception:
                metrics = {"raw": r[4]}
        out.append({
            "run_id": r[0],
            "created_at": r[1],
            "status": r[2],
            "model_dir": r[3],
            "metrics": metrics,
            "error": r[5],
        })
    return JSONResponse({"runs": out})


@app.get("/models")
def list_model_versions(limit: int = 20):
    limit = max(1, min(200, int(limit)))
    rows = db_query("SELECT id, created_at, run_id, model_dir, metrics_json, notes FROM model_versions ORDER BY created_at DESC LIMIT ?", (limit,))
    out = []
    for r in rows:
        metrics = None
        if r[4]:
            try:
                metrics = json.loads(r[4])
            except Exception:
                metrics = {"raw": r[4]}
        out.append({
            "model_version_id": r[0],
            "created_at": r[1],
            "run_id": r[2],
            "model_dir": r[3],
            "metrics": metrics,
            "notes": r[5],
        })
    return JSONResponse({"models": out})


@app.post("/predict")
async def predict(image: UploadFile = File(...)):
    ext = safe_ext(image.filename or "")
    if ext and ext not in ALLOWED_IMAGE_EXTS:
        raise HTTPException(status_code=400, detail=f"Unsupported image extension: {ext}")
    content = read_limited(image, MAX_UPLOAD_BYTES)
    save_upload("predict_image", image.filename, content, meta={})
    return JSONResponse(predict_image_bytes(content))


@app.delete("/example/{example_id}")
def delete_example(example_id: str):
    rows = db_query("SELECT image_path FROM examples WHERE id=?", (example_id,))
    if not rows:
        raise HTTPException(status_code=404, detail="Example not found")
    image_path = rows[0][0]
    db_execute("DELETE FROM examples WHERE id=?", (example_id,))
    try:
        if image_path and os.path.exists(image_path):
            os.remove(image_path)
    except Exception:
        pass
    return JSONResponse({"deleted": True, "example_id": example_id})


def main():
    host = os.environ.get("HOST", "0.0.0.0")
    port = int(os.environ.get("PORT", "8000"))
    uvicorn.run(app, host=host, port=port)


if __name__ == "__main__":
    main()